return 'p1'
if all(g(i) == 'p1' for i in m(h)):
return 'v1'
if any(g(i) == 'v1' for i in m(h)):
return 'p2'
if all(g(i) == 'p1' or g(i) == 'p2' for i in m(h)):
return 'v1/2'
for i in range(1, 109):
if g(i) == 'v1':
